1	package handler
2	
3	import (
4		"errors"
5	
6		"clinic-admin-suite/internal/api/httpx"
7		"clinic-admin-suite/internal/api/middleware"
8		"clinic-admin-suite/internal/config"
9		"clinic-admin-suite/internal/service"
10	
11		"github.com/gofiber/fiber/v2"
12	)
13	
14	type AuthHandler struct {
15		authService *service.AuthService
16		config      config.Config
17	}
18	
19	func NewAuthHandler(authService *service.AuthService, cfg config.Config) *AuthHandler {
20		return &AuthHandler{
21			authService: authService,
22			config:      cfg,
23		}
24	}
25	
26	type loginRequest struct {
27		Username string `json:"username"`
28		Password string `json:"password"`
29	}
30	
31	func (h *AuthHandler) Login(c *fiber.Ctx) error {
32		var req loginRequest
33		if err := c.BodyParser(&req); err != nil {
34			return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "Invalid request payload", nil)
35		}
36	
37		result, err := h.authService.Login(c.UserContext(), service.LoginInput{
38			Username:  req.Username,
39			Password:  req.Password,
40			RequestID: httpx.RequestID(c),
41			IP:        c.IP(),
42			UserAgent: c.Get("User-Agent"),
43		})
44		if err != nil {
45			if errors.Is(err, service.ErrInvalidCredentials) {
46				return httpx.Error(c, fiber.StatusUnauthorized, "AUTH_INVALID_CREDENTIALS", "Invalid username or password", nil)
47			}
48	
49			var accountLocked *service.AccountLockedError
50			if errors.As(err, &accountLocked) {
51				return httpx.Error(c, fiber.StatusForbidden, "AUTH_FORBIDDEN", "Account is temporarily locked", fiber.Map{
52					"locked_until": accountLocked.Until.Format("2006-01-02T15:04:05Z07:00"),
53				})
54			}
55	
56			return httpx.Error(c, fiber.StatusInternalServerError, "INTERNAL_ERROR", "Failed to process login", nil)
57		}
58	
59		c.Cookie(&fiber.Cookie{
60			Name:     h.config.SessionCookieName,
61			Value:    result.Token,
62			Path:     "/",
63			Expires:  result.ExpiresAt,
64			HTTPOnly: true,
65			Secure:   h.config.CookieSecure,
66			SameSite: "Strict",
67		})
68	
69		return httpx.OK(c, fiber.StatusOK, fiber.Map{
70			"user": fiber.Map{
71				"id":       result.User.ID,
72				"username": result.User.Username,
73				"role":     result.User.Role,
74			},
75			"permissions":        result.Permission,
76			"session_expires_at": result.ExpiresAt.Format("2006-01-02T15:04:05Z07:00"),
77		})
78	}
79	
80	func (h *AuthHandler) Me(c *fiber.Ctx) error {
81		authContext, ok := middleware.CurrentAuth(c)
82		if !ok {
83			return httpx.Error(c, fiber.StatusUnauthorized, "AUTH_INVALID_CREDENTIALS", "Authentication required", nil)
84		}
85	
86		return httpx.OK(c, fiber.StatusOK, fiber.Map{
87			"user": fiber.Map{
88				"id":       authContext.User.ID,
89				"username": authContext.User.Username,
90				"role":     authContext.User.Role,
91			},
92			"permissions": authContext.Permissions,
93		})
94	}
