1	package handler
2	
3	import "github.com/gofiber/fiber/v2"
4	
5	type CacheUIHandler struct{}
6	
7	func NewCacheUIHandler() *CacheUIHandler {
8		return &CacheUIHandler{}
9	}
10	
11	func (h *CacheUIHandler) LRUSimulator(c *fiber.Ctx) error {
12		c.Type("html", "utf-8")
13		return c.SendString(`
14	<section id="cache-lru-simulator" class="cache-simulator">
15	  <h3>Client LRU Cache Simulator</h3>
16	  <p>Simulates shared-workstation cache with limits: 2GB total or 200 items.</p>
17	  <form id="cache-put-form" hx-on:submit="event.preventDefault(); window.clinicCache.putFromForm();">
18	    <label>Item Key <input type="text" id="cache-item-key" value="exercise:1:video" /></label>
19	    <label>Size (bytes) <input type="number" id="cache-item-size" value="1048576" min="1" /></label>
20	    <label>Hash <input type="text" id="cache-item-hash" value="sha256_demo" /></label>
21	    <button type="submit">Cache Item</button>
22	  </form>
23	  <button type="button" onclick="window.clinicCache.render()">Refresh View</button>
24	  <pre id="cache-lru-output"></pre>
25	  <script>
26	  (function() {
27	    const MAX_BYTES = 2 * 1024 * 1024 * 1024;
28	    const MAX_ITEMS = 200;
29	
30	    function storageKey() {
31	      const user = localStorage.getItem('clinic:user') || 'anonymous';
32	      const device = localStorage.getItem('clinic:device') || 'shared_workstation';
33	      return 'clinic:lru:' + user + ':' + device;
34	    }
35	
36	    function nowISO() {
37	      return new Date().toISOString();
38	    }
39	
40	    function loadIndex() {
41	      try {
42	        const raw = localStorage.getItem(storageKey());
43	        if (!raw) {
44	          return { total_bytes: 0, items: {} };
45	        }
46	        const parsed = JSON.parse(raw);
47	        if (!parsed || typeof parsed !== 'object') {
48	          return { total_bytes: 0, items: {} };
49	        }
50	        parsed.items = parsed.items || {};
51	        parsed.total_bytes = Number(parsed.total_bytes || 0);
52	        return parsed;
53	      } catch (err) {
54	        return { total_bytes: 0, items: {} };
55	      }
56	    }
57	
58	    function saveIndex(index) {
59	      localStorage.setItem(storageKey(), JSON.stringify(index));
60	    }
61	
62	    function recalcTotal(index) {
63	      index.total_bytes = Object.values(index.items).reduce((sum, item) => sum + Number(item.size_bytes || 0), 0);
64	      return index.total_bytes;
65	    }
66	
67	    function evict(index) {
68	      recalcTotal(index);
69	      let entries = Object.entries(index.items);
70	      entries.sort((a, b) => {
71	        const left = new Date(a[1].last_accessed_at || a[1].created_at || 0).getTime();
72	        const right = new Date(b[1].last_accessed_at || b[1].created_at || 0).getTime();
73	        return left - right;
74	      });
75	
76	      while (entries.length > MAX_ITEMS || index.total_bytes > MAX_BYTES) {
77	        const victim = entries.shift();
78	        if (!victim) {
79	          break;
80	        }
81	        const victimKey = victim[0];
82	        const victimSize = Number(victim[1].size_bytes || 0);
83	        delete index.items[victimKey];
84	        index.total_bytes = Math.max(0, index.total_bytes - victimSize);
85	      }
86	    }
87	
88	    function putItem(key, sizeBytes, hash) {
89	      const index = loadIndex();
90	      const normalizedKey = String(key || '').trim();
91	      const normalizedHash = String(hash || '').trim();
92	      const normalizedSize = Math.max(1, Number(sizeBytes || 0));
93	      if (!normalizedKey || !normalizedHash || !Number.isFinite(normalizedSize)) {
94	        return;
95	      }
96	
97	      const current = index.items[normalizedKey];
98	      if (current) {
99	        index.total_bytes = Math.max(0, index.total_bytes - Number(current.size_bytes || 0));
100	      }
101	
102	      const item = {
103	        key: normalizedKey,
104	        size_bytes: normalizedSize,
105	        content_hash: normalizedHash,
106	        created_at: current ? current.created_at : nowISO(),
107	        last_accessed_at: nowISO()
108	      };
109	      index.items[normalizedKey] = item;
110	      index.total_bytes += normalizedSize;
111	
112	      evict(index);
113	      saveIndex(index);
114	    }
115	
116	    function touchItem(key) {
117	      const index = loadIndex();
118	      const item = index.items[key];
119	      if (!item) {
120	        return false;
121	      }
122	      item.last_accessed_at = nowISO();
123	      index.items[key] = item;
124	      saveIndex(index);
125	      return true;
126	    }
127	
128	    function invalidateIfHashMismatch(key, expectedHash) {
129	      const index = loadIndex();
130	      const item = index.items[key];
131	      if (!item) {
132	        return;
133	      }
134	      if (item.content_hash !== expectedHash) {
135	        index.total_bytes = Math.max(0, index.total_bytes - Number(item.size_bytes || 0));
136	        delete index.items[key];
137	        saveIndex(index);
138	      }
139	    }
140	
141	    function render() {
142	      const output = document.getElementById('cache-lru-output');
143	      if (!output) {
144	        return;
145	      }
146	      const index = loadIndex();
147	      const entries = Object.values(index.items).sort((a, b) => {
148	        const left = new Date(b.last_accessed_at || b.created_at || 0).getTime();
149	        const right = new Date(a.last_accessed_at || a.created_at || 0).getTime();
150	        return left - right;
151	      });
152	
153	      output.textContent = JSON.stringify({
154	        limit_bytes: MAX_BYTES,
155	        limit_items: MAX_ITEMS,
156	        total_bytes: index.total_bytes,
157	        item_count: entries.length,
158	        items: entries
159	      }, null, 2);
160	    }
161	
162	    window.clinicCache = {
163	      put: putItem,
164	      get: touchItem,
165	      invalidateIfHashMismatch,
166	      render,
167	      putFromForm: function() {
168	        const key = document.getElementById('cache-item-key').value;
169	        const size = document.getElementById('cache-item-size').value;
170	        const hash = document.getElementById('cache-item-hash').value;
171	        putItem(key, size, hash);
172	        render();
173	      }
174	    };
175	
176	    render();
177	  })();
178	  </script>
179	</section>
180	`)
181	}
