17		"golang.org/x/crypto/bcrypt"
18	)
19	
20	var (
21		ErrInvalidCredentials = errors.New("auth: invalid credentials")
22		ErrUnauthenticated    = errors.New("auth: unauthenticated")
23	)
24	
25	type AccountLockedError struct {
26		Until time.Time
27	}
28	
29	func (e *AccountLockedError) Error() string {
30		return fmt.Sprintf("auth: account locked until %s", e.Until.Format(time.RFC3339))
31	}
32	
33	type AuthService struct {
34		users      repository.UserRepository
35		sessions   repository.SessionRepository
36		audit      *AuditService
37		bcryptCost int
38		sessionTTL time.Duration
39	}
40	
41	func NewAuthService(users repository.UserRepository, sessions repository.SessionRepository, audit *AuditService, bcryptCost int, sessionTTL time.Duration) *AuthService {
42		if bcryptCost < bcrypt.MinCost {
43			bcryptCost = bcrypt.DefaultCost
44		}
45		if sessionTTL <= 0 {
46			sessionTTL = 15 * time.Minute
47		}
48	
49		return &AuthService{
50			users:      users,
51			sessions:   sessions,
52			audit:      audit,
53			bcryptCost: bcryptCost,
54			sessionTTL: sessionTTL,
55		}
56	}
57	
58	type LoginInput struct {
59		Username  string
60		Password  string
61		RequestID string
62		IP        string
63		UserAgent string
64	}
65	
66	type LoginResult struct {
67		User       *domain.User
68		Token      string
69		ExpiresAt  time.Time
70		Permission []domain.Permission
71	}
72	
73	func (s *AuthService) Login(ctx context.Context, input LoginInput) (*LoginResult, error) {
74		now := time.Now().UTC()
75		username := strings.TrimSpace(input.Username)
76	
77		if username == "" || input.Password == "" {
78			if err := s.audit.LogLoginFailure(ctx, nil, username, "missing_credentials", input.RequestID, input.IP, input.UserAgent); err != nil {
79				return nil, err
80			}
81			return nil, ErrInvalidCredentials
82		}
83	
84		user, err := s.users.GetByUsername(ctx, username)
85		if err != nil {
86			if errors.Is(err, repository.ErrNotFound) {
87				if logErr := s.audit.LogLoginFailure(ctx, nil, username, "invalid_credentials", input.RequestID, input.IP, input.UserAgent); logErr != nil {
88					return nil, logErr
89				}
90				return nil, ErrInvalidCredentials
91			}
92			return nil, fmt.Errorf("lookup user: %w", err)
93		}
94	
95		if user.LockedUntil != nil && now.Before(*user.LockedUntil) {
96			if err := s.audit.LogLoginFailure(ctx, &user.ID, username, "account_locked", input.RequestID, input.IP, input.UserAgent); err != nil {
97				return nil, err
98			}
99			return nil, &AccountLockedError{Until: *user.LockedUntil}
100		}
101	
102		if err := bcrypt.CompareHashAndPassword([]byte(user.PasswordHash), []byte(input.Password)); err != nil {
103			failedCount := user.FailedLoginCount + 1
104			lockedUntil := calculateLockout(now, failedCount)
105	
106			if updateErr := s.users.RecordFailedLogin(ctx, user.ID, failedCount, lockedUntil); updateErr != nil {
107				return nil, fmt.Errorf("record failed login: %w", updateErr)
108			}
109	
110			reason := "invalid_credentials"
111			if lockedUntil != nil {
112				reason = "lockout_backoff"
113			}
114	
115			if auditErr := s.audit.LogLoginFailure(ctx, &user.ID, username, reason, input.RequestID, input.IP, input.UserAgent); auditErr != nil {
116				return nil, auditErr
117			}
118	
119			return nil, ErrInvalidCredentials
120		}
121	
122		if err := s.users.ResetFailedLogins(ctx, user.ID); err != nil {
123			return nil, fmt.Errorf("reset failed login state: %w", err)
124		}
125	
126		rawToken, err := randomToken(32)
127		if err != nil {
128			return nil, fmt.Errorf("generate session token: %w", err)
129		}
130	
131		expiresAt := now.Add(s.sessionTTL)
132		session := &domain.Session{
133			UserID:     user.ID,
134			TokenHash:  hashToken(rawToken),
135			CreatedAt:  now,
136			ExpiresAt:  expiresAt,
137			LastSeenAt: now,
138		}
139	
140		if err := s.sessions.Create(ctx, session); err != nil {
141			return nil, fmt.Errorf("create session: %w", err)
142		}
143	
144		if err := s.audit.LogLoginSuccess(ctx, user.ID, user.Username, input.RequestID, input.IP, input.UserAgent); err != nil {
145			return nil, err
146		}
147	
148		return &LoginResult{
149			User:       user,
150			Token:      rawToken,
151			ExpiresAt:  expiresAt,
152			Permission: domain.PermissionsForRole(user.Role),
153		}, nil
154	}
155	
156	func (s *AuthService) AuthenticateToken(ctx context.Context, rawToken string) (*domain.User, *domain.Session, error) {
157		rawToken = strings.TrimSpace(rawToken)
158		if rawToken == "" {
159			return nil, nil, ErrUnauthenticated
160		}
161	
162		now := time.Now().UTC()
163		session, user, err := s.sessions.GetActiveByTokenHash(ctx, hashToken(rawToken), now)
164		if err != nil {
165			if errors.Is(err, repository.ErrNotFound) {
166				return nil, nil, ErrUnauthenticated
167			}
168			return nil, nil, fmt.Errorf("fetch active session: %w", err)
169		}
170	
171		newExpiresAt := now.Add(s.sessionTTL)
172		if err := s.sessions.TouchActivity(ctx, session.ID, now, newExpiresAt); err != nil {
173			return nil, nil, fmt.Errorf("touch session activity: %w", err)
174		}
175		session.LastSeenAt = now
176		session.ExpiresAt = newExpiresAt
177	
178		return user, session, nil
179	}
180	
181	func (s *AuthService) EnsureBootstrapAdmin(ctx context.Context, username, password string) error {
182		username = strings.TrimSpace(username)
183		if username == "" || password == "" {
184			return nil
185		}
186	
187		if err := ValidatePasswordPolicy(password); err != nil {
188			return fmt.Errorf("bootstrap admin password policy: %w", err)
189		}
190	
191		_, err := s.users.GetByUsername(ctx, username)
192		if err == nil {
193			return nil
194		}
195		if !errors.Is(err, repository.ErrNotFound) {
196			return fmt.Errorf("check bootstrap admin user: %w", err)
197		}
198	
199		hash, err := bcrypt.GenerateFromPassword([]byte(password), s.bcryptCost)
200		if err != nil {
201			return fmt.Errorf("hash bootstrap admin password: %w", err)
202		}
203	
204		user := &domain.User{
205			Username:     username,
206			PasswordHash: string(hash),
207			Role:         string(domain.RoleAdmin),
208		}
209	
210		if err := s.users.Create(ctx, user); err != nil {
211			return fmt.Errorf("create bootstrap admin user: %w", err)
212		}
213	
214		return nil
215	}
216	
217	func calculateLockout(now time.Time, failedCount int) *time.Time {
218		if failedCount < 5 {
219			return nil
220		}
221	
222		backoffSeconds := 30 * (1 << (failedCount - 5))
223		if backoffSeconds > 1800 {
224			backoffSeconds = 1800
225		}
226	
227		lockedUntil := now.Add(time.Duration(backoffSeconds) * time.Second)
228		return &lockedUntil
229	}
230	
231	func randomToken(size int) (string, error) {
232		b := make([]byte, size)
233		if _, err := rand.Read(b); err != nil {
234			return "", err
235		}
236		return base64.RawURLEncoding.EncodeToString(b), nil
237	}
238	
239	func hashToken(raw string) string {
240		sum := sha256.Sum256([]byte(raw))
241		return hex.EncodeToString(sum[:])
242	}
