1	package service
2	
3	import (
4		"context"
5		"database/sql"
6		"fmt"
7		"sort"
8		"strings"
9		"time"
10	
11		"clinic-admin-suite/internal/domain"
12		"clinic-admin-suite/internal/repository"
13	)
14	
15	type KPIService struct {
16		db         *sql.DB
17		workOrders repository.WorkOrderRepository
18		rollups    repository.KPIRollupRepository
19		jobRuns    *JobRunService
20	}
21	
22	func NewKPIService(db *sql.DB, workOrders repository.WorkOrderRepository, rollups repository.KPIRollupRepository, jobRuns *JobRunService) *KPIService {
23		return &KPIService{
24			db:         db,
25			workOrders: workOrders,
26			rollups:    rollups,
27			jobRuns:    jobRuns,
28		}
29	}
30	
31	type ServiceDeliveryQuery struct {
32		From    time.Time
33		To      time.Time
34		GroupBy string
35	}
36	
37	func (s *KPIService) QueryServiceDelivery(ctx context.Context, query ServiceDeliveryQuery) ([]domain.KPIServiceRollup, error) {
38		groupBy := strings.TrimSpace(strings.ToLower(query.GroupBy))
39		if groupBy == "" {
40			groupBy = "hour"
41		}
42		if groupBy != "hour" && groupBy != "day" && groupBy != "week" && groupBy != "service_type" {
43			return nil, fmt.Errorf("%w: group_by must be hour, day, week, or service_type", ErrValidation)
44		}
45	
46		from := query.From.UTC()
47		to := query.To.UTC()
48		if !to.After(from) {
49			return nil, fmt.Errorf("%w: to must be greater than from", ErrValidation)
50		}
51	
52		now := time.Now().UTC()
53		currentHourStart := now.Truncate(time.Hour)
54	
55		hourly := make([]domain.KPIServiceRollup, 0)
56	
57		historyTo := minTime(to, currentHourStart)
58		if historyTo.After(from) {
59			history, err := s.rollups.List(ctx, repository.KPIRollupFilter{
60				BucketGranularity: "hour",
61				From:              &from,
62				To:                &historyTo,
63			})
64			if err != nil {
65				return nil, err
66			}
67			hourly = append(hourly, history...)
68		}
69	
70		realtimeFrom := maxTime(from, currentHourStart)
71		if to.After(realtimeFrom) {
72			realtime, err := s.workOrders.AggregateMetrics(ctx, realtimeFrom, to)
73			if err != nil {
74				return nil, err
75			}
76			for i := range realtime {
77				realtime[i].BucketStart = realtimeFrom.Truncate(time.Hour)
78				realtime[i].BucketGranularity = "hour"
79			}
80			hourly = append(hourly, realtime...)
81		}
82	
83		return aggregateMetrics(hourly, groupBy), nil
84	}
85	
86	func (s *KPIService) ComputeHourlyRollup(ctx context.Context, bucketStart time.Time) error {
87		startRun := time.Now().UTC()
88		status := "success"
89		summary := map[string]any{
90			"bucket_start": bucketStart.UTC().Format(time.RFC3339),
91		}
92	
93		err := s.computeHourlyRollup(ctx, bucketStart)
94		if err != nil {
95			status = "failure"
96			summary["error"] = err.Error()
97		} else {
98			summary["result"] = "ok"
99		}
100	
101		_ = s.jobRuns.Record(ctx, JobRunInput{
102			JobType:    "kpi_rollup_hourly",
103			StartedAt:  startRun,
104			FinishedAt: time.Now().UTC(),
105			Status:     status,
106			Summary:    summary,
107		})
108	
109		return err
110	}
111	
112	func (s *KPIService) computeHourlyRollup(ctx context.Context, bucketStart time.Time) error {
113		bucketStart = bucketStart.UTC().Truncate(time.Hour)
114		bucketEnd := bucketStart.Add(time.Hour)
115	
116		tx, err := s.db.BeginTx(ctx, nil)
117		if err != nil {
118			return fmt.Errorf("begin kpi rollup tx: %w", err)
119		}
120		defer tx.Rollback()
121	
122		metrics, err := s.workOrders.AggregateMetricsTx(ctx, tx, bucketStart, bucketEnd)
123		if err != nil {
124			return err
125		}
126	
127		for i := range metrics {
128			metrics[i].BucketStart = bucketStart
129			metrics[i].BucketGranularity = "hour"
130			if err := s.rollups.UpsertTx(ctx, tx, &metrics[i]); err != nil {
131				return err
132			}
133		}
134	
135		if err := tx.Commit(); err != nil {
136			return fmt.Errorf("commit kpi rollup tx: %w", err)
137		}
138	
139		return nil
140	}
141	
142	func (s *KPIService) StartHourlyRollupTicker(ctx context.Context) {
143		previousHour := time.Now().UTC().Truncate(time.Hour).Add(-time.Hour)
144		_ = s.ComputeHourlyRollup(ctx, previousHour)
145	
146		ticker := time.NewTicker(time.Hour)
147		defer ticker.Stop()
148	
149		for {
150			select {
151			case <-ctx.Done():
152				return
153			case t := <-ticker.C:
154				_ = s.ComputeHourlyRollup(ctx, t.UTC().Truncate(time.Hour).Add(-time.Hour))
155			}
156		}
157	}
158	
159	func aggregateMetrics(hourly []domain.KPIServiceRollup, groupBy string) []domain.KPIServiceRollup {
160		if groupBy == "hour" {
161			return hourly
162		}
163	
164		type key struct {
165			bucketStart int64
166			serviceType string
167		}
168	
169		agg := make(map[key]*domain.KPIServiceRollup)
170		for _, item := range hourly {
171			bucket := item.BucketStart.UTC()
172			switch groupBy {
173			case "day":
174				bucket = time.Date(bucket.Year(), bucket.Month(), bucket.Day(), 0, 0, 0, 0, time.UTC)
175			case "week":
176				bucket = weekStartUTC(bucket)
177			case "service_type":
178				bucket = time.Unix(0, 0).UTC()
179			}
180	
181			k := key{bucketStart: bucket.Unix(), serviceType: item.ServiceType}
182			existing, ok := agg[k]
183			if !ok {
184				existing = &domain.KPIServiceRollup{
185					BucketStart:       bucket,
186					BucketGranularity: groupBy,
187					ServiceType:       item.ServiceType,
188				}
189				agg[k] = existing
190			}
191	
192			existing.Total += item.Total
193			existing.Completed += item.Completed
194			existing.OnTime15m += item.OnTime15m
195		}
196	
197		out := make([]domain.KPIServiceRollup, 0, len(agg))
198		for _, item := range agg {
199			item.ExecutionRate = computeExecutionRate(item.Total, item.Completed)
200			item.TimelinessRate = computeTimelinessRate(item.Completed, item.OnTime15m)
201			out = append(out, *item)
202		}
203	
204		sort.Slice(out, func(i, j int) bool {
205			if out[i].BucketStart.Equal(out[j].BucketStart) {
206				return out[i].ServiceType < out[j].ServiceType
207			}
208			return out[i].BucketStart.Before(out[j].BucketStart)
209		})
210	
211		return out
212	}
213	
214	func weekStartUTC(t time.Time) time.Time {
215		t = t.UTC()
216		weekday := int(t.Weekday())
217		if weekday == 0 {
218			weekday = 7
219		}
220		start := t.AddDate(0, 0, -(weekday - 1))
221		return time.Date(start.Year(), start.Month(), start.Day(), 0, 0, 0, 0, time.UTC)
222	}
223	
224	func minTime(a, b time.Time) time.Time {
225		if a.Before(b) {
226			return a
227		}
228		return b
229	}
230	
231	func maxTime(a, b time.Time) time.Time {
232		if a.After(b) {
233			return a
234		}
235		return b
236	}
237	
238	func computeExecutionRate(total, completed int64) float64 {
239		if total == 0 {
240			return 0
241		}
242		return float64(completed) * 100 / float64(total)
243	}
244	
245	func computeTimelinessRate(completed, onTime int64) float64 {
246		if completed == 0 {
247			return 0
248		}
249		return float64(onTime) * 100 / float64(completed)
250	}
