236	func (h *AppPagesHandler) PanelScheduling(c *fiber.Ctx) error {
237		templates, _ := h.templates.ListTemplates(c.UserContext())
238		drafts, _ := h.templates.ListDrafts(c.UserContext(), nil)
239	
240		sort.Slice(drafts, func(i, j int) bool { return drafts[i].CreatedAt.After(drafts[j].CreatedAt) })
241	
242		var b strings.Builder
243		b.WriteString(`<section class="view active"><div class="grid two"><article class="card"><h3>Create Exam Template</h3><form class="stack-form" hx-post="/ui/scheduling/templates" hx-target="#panel"><label>Title<input name="title" required></label><label>Subject<input name="subject" required></label><label>Duration Minutes<input type="number" name="duration_minutes" value="90" required></label><label>Room ID<input type="number" name="room_id" required></label><label>Proctor ID<input type="number" name="proctor_id" required></label><label>Candidate IDs<input name="candidate_ids" placeholder="1001,1002" required></label><label>Window Label<input name="window_label" value="Morning"></label><label>Window Start (RFC3339)<input name="window_start_at" placeholder="2026-03-25T09:00:00Z" required></label><label>Window End (RFC3339)<input name="window_end_at" placeholder="2026-03-25T12:00:00Z" required></label><button type="submit">Save Template</button></form></article><article class="card"><h3>Generate Session Draft</h3><form class="stack-form" hx-post="/ui/scheduling/drafts/generate" hx-target="#panel"><label>Template ID<input type="number" name="template_id" required></label><label>Window ID<input type="number" name="window_id" required></label><label>Start At (optional RFC3339)<input name="start_at"></label><button type="submit">Generate Draft</button></form></article></div>`)
244	
245		b.WriteString(`<article class="card"><h3>Exam Templates</h3><div class="stack">`)
246		if len(templates) == 0 {
247			b.WriteString(`<p class="hint">No templates configured.</p>`)
248		}
249		for _, item := range templates {
250			b.WriteString(`<div class="exercise-row"><div><strong>#` + strconv.FormatInt(item.ID, 10) + ` ` + html.EscapeString(item.Title) + `</strong><div>` + html.EscapeString(item.Subject) + ` (` + strconv.Itoa(item.DurationMinutes) + ` min)</div></div><div>room ` + strconv.FormatInt(item.RoomID, 10) + ` / proctor ` + strconv.FormatInt(item.ProctorID, 10) + `</div></div>`)
251			for _, w := range item.Windows {
252				b.WriteString(`<div class="hint">window #` + strconv.FormatInt(w.ID, 10) + ` ` + html.EscapeString(w.Label) + `: ` + w.WindowStartAt.Format("01/02/2006 15:04") + `-` + w.WindowEndAt.Format("15:04") + `</div>`)
253			}
254		}
255		b.WriteString(`</div></article>`)
256	
257		b.WriteString(`<article class="card"><h3>Session Drafts (Adjust Before Publish)</h3><div class="stack">`)
258		if len(drafts) == 0 {
259			b.WriteString(`<p class="hint">No session drafts yet.</p>`)
260		}
261		for _, item := range drafts {
262			b.WriteString(`<div class="exercise-row"><div><strong>Draft #` + strconv.FormatInt(item.ID, 10) + `</strong><div>` + item.StartAt.Format(time.RFC3339) + ` to ` + item.EndAt.Format(time.RFC3339) + `</div></div><div>Status: ` + html.EscapeString(item.Status) + `</div></div>`)
263			if len(item.Conflicts) > 0 {
264				b.WriteString(`<pre class="output">conflicts: ` + html.EscapeString(fmt.Sprintf("%v", item.Conflicts)) + `</pre>`)
265			}
266			if item.Status != "published" {
267				b.WriteString(`<form class="stack-form" hx-post="/ui/scheduling/drafts/` + strconv.FormatInt(item.ID, 10) + `/adjust" hx-target="#panel"><label>Start At<input name="start_at" value="` + item.StartAt.Format(time.RFC3339) + `"></label><label>End At<input name="end_at" value="` + item.EndAt.Format(time.RFC3339) + `"></label><button type="submit">Adjust Time Block</button></form><button hx-post="/ui/scheduling/drafts/` + strconv.FormatInt(item.ID, 10) + `/publish" hx-target="#panel">Publish Session</button>`)
268			}
269		}
270		b.WriteString(`</div></article></section>`)
271		return c.SendString(b.String())
272	}
