470	func parseIDCSV(raw string) []int64 {
471		parts := strings.Split(raw, ",")
472		out := make([]int64, 0, len(parts))
473		for _, part := range parts {
474			v, err := strconv.ParseInt(strings.TrimSpace(part), 10, 64)
475			if err == nil && v > 0 {
476				out = append(out, v)
477			}
478		}
479		return out
