43	func (s *MediaService) Ingest(ctx context.Context, input IngestMediaInput) (*domain.MediaAsset, error) {
44		if input.ExerciseID <= 0 {
45			return nil, fmt.Errorf("%w: exercise_id must be positive", ErrValidation)
46		}
47		if strings.TrimSpace(input.MediaType) == "" {
48			return nil, fmt.Errorf("%w: media_type is required", ErrValidation)
49		}
50		if input.Reader == nil {
51			return nil, fmt.Errorf("%w: media file is required", ErrValidation)
52		}
53	
54		if _, err := s.exercises.GetByID(ctx, input.ExerciseID); err != nil {
55			if errors.Is(err, repository.ErrNotFound) {
56				return nil, fmt.Errorf("%w: exercise not found", ErrNotFound)
57			}
58			return nil, err
59		}
60	
61		root := s.mediaRoot
62		if root == "" {
63			root = filepath.Join(".", "data", "media")
64		}
65	
66		now := time.Now().UTC()
67		yy := now.Format("06")
68		mm := now.Format("01")
69	
70		variant := sanitizeVariant(input.Variant)
71		ext := strings.ToLower(strings.TrimSpace(filepath.Ext(input.Filename)))
72		if ext == "" {
73			ext = ".bin"
74		}
75	
76		mediaToken, err := randomHexToken(10)
77		if err != nil {
78			return nil, fmt.Errorf("generate media token: %w", err)
79		}
80

80	
81		relDir := filepath.ToSlash(filepath.Join(yy, mm))
82		filename := mediaToken + "_" + variant + ext
83		relPath := filepath.ToSlash(filepath.Join(relDir, filename))
84		absDir := filepath.Join(root, yy, mm)
85		absPath := filepath.Join(absDir, filename)
86	
87		if err := os.MkdirAll(absDir, 0o755); err != nil {
88			return nil, fmt.Errorf("create media directory: %w", err)
89		}
90	
91		outFile, err := os.Create(absPath)
92		if err != nil {
93			return nil, fmt.Errorf("create media file: %w", err)
94		}
95	
96		hasher := sha256.New()
97		bytesWritten, copyErr := io.Copy(io.MultiWriter(outFile, hasher), input.Reader)
98		closeErr := outFile.Close()
99		if copyErr != nil {
100			_ = os.Remove(absPath)
101			return nil, fmt.Errorf("copy media file: %w", copyErr)
102		}
103		if closeErr != nil {
104			_ = os.Remove(absPath)
105			return nil, fmt.Errorf("close media file: %w", closeErr)
106		}
107	
108		asset := &domain.MediaAsset{
109			ExerciseID:     input.ExerciseID,
110			MediaType:      strings.TrimSpace(input.MediaType),
111			Path:           relPath,
112			ChecksumSHA256: hex.EncodeToString(hasher.Sum(nil)),
113			DurationMS:     input.DurationMS,
114			Bytes:          bytesWritten,
115			Variant:        variant,
116		}
117	
118		if err := s.media.Create(ctx, asset); err != nil {
119			_ = os.Remove(absPath)
120			return nil, err
121		}
122	
123		return asset, nil
124	}
