151	func sanitizeVariant(variant string) string {
152		v := strings.TrimSpace(strings.ToLower(variant))
153		if v == "" {
154			return "original"
155		}
156		v = strings.ReplaceAll(v, " ", "_")
157		v = strings.ReplaceAll(v, "-", "_")
158		b := strings.Builder{}
159		for _, r := range v {
160			if (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') || r == '_' {
161				b.WriteRune(r)
162			}
163		}
164		out := b.String()
165		if out == "" {
166			return "original"
167		}
168		return out
169	}
