242	func (s *PaymentService) Refund(ctx context.Context, input RefundPaymentInput) (*domain.Payment, error) {
243		if input.PaymentID <= 0 {
244			return nil, fmt.Errorf("%w: payment_id must be a positive integer", ErrValidation)
245		}
246		if input.AmountCents <= 0 {
247			return nil, fmt.Errorf("%w: amount_cents must be positive", ErrValidation)
248		}
249		reason := strings.TrimSpace(input.Reason)
250		if reason == "" {
251			return nil, fmt.Errorf("%w: reason is required", ErrValidation)
252		}
253	
254		original, err := s.payments.GetByID(ctx, input.PaymentID)
255		if err != nil {
256			return nil, err
257		}
258		if original.Status != domain.PaymentStatusSucceeded {
259			return nil, fmt.Errorf("%w: only succeeded payments can be refunded", ErrConflict)
260		}
261		if original.AmountCents <= 0 {
262			return nil, fmt.Errorf("%w: refund source payment amount is invalid", ErrConflict)
263		}
264		if input.AmountCents > original.AmountCents {
265			return nil, fmt.Errorf("%w: refund amount exceeds original payment amount", ErrValidation)
266		}
267	
268		now := time.Now().UTC()
269		externalRef := fmt.Sprintf("refund_%d_%d", original.ID, now.UnixNano())
270	
271		var idemPtr *string
272		if strings.TrimSpace(input.IdempotencyKey) != "" {
273			v := strings.TrimSpace(input.IdempotencyKey)
274			idemPtr = &v
275		}
276	
277		refundPayment := &domain.Payment{
278			ExternalRef:    &externalRef,
279			Method:         "refund",
280			Gateway:        original.Gateway,
281			AmountCents:    -input.AmountCents,
282			Currency:       original.Currency,
283			Status:         domain.PaymentStatusSucceeded,
284			ReceivedAt:     now,
285			ShiftID:        original.ShiftID,
286			IdempotencyKey: idemPtr,
287		}
288	
289		tx, err := s.db.BeginTx(ctx, nil)
290		if err != nil {
291			return nil, fmt.Errorf("begin refund tx: %w", err)
292		}
293		defer tx.Rollback()
294	
295		if err := s.payments.CreateTx(ctx, tx, refundPayment); err != nil {
296			return nil, err
297		}
298	
299		eventPayload, err := json.Marshal(map[string]any{
300			"original_payment_id": original.ID,
301			"refund_payment_id":   refundPayment.ID,
302			"amount_cents":        input.AmountCents,
303			"reason":              reason,
304		})
305		if err != nil {
306			return nil, fmt.Errorf("marshal refund event payload: %w", err)
307		}
308	
309		if err := s.paymentEvents.CreateTx(ctx, tx, &domain.PaymentEvent{
310			PaymentID: original.ID,
311			EventType: "payment.refund_issued",
312			Payload:   string(eventPayload),
313			CreatedAt: now,
314		}); err != nil {
315			return nil, err
316		}
317	
318		if err := s.paymentEvents.CreateTx(ctx, tx, &domain.PaymentEvent{
319			PaymentID: refundPayment.ID,
320			EventType: "payment.refund_created",
321			Payload:   string(eventPayload),
322			CreatedAt: now,
323		}); err != nil {
324			return nil, err
325		}
326	
327		if err := s.audit.LogEventTx(ctx, tx, AuditLogInput{
328			ActorID:      input.ActorID,
329			Action:       "payment.refund",
330			ResourceType: "payment",
331			ResourceID:   fmt.Sprintf("%d", original.ID),
332			After: map[string]any{
333				"original_payment_id": original.ID,
334				"refund_payment_id":   refundPayment.ID,
335				"amount_cents":        input.AmountCents,
336				"reason":              reason,
337			},
338			RequestID: fallbackRequestID(input.RequestID),
339		}); err != nil {
340			return nil, err
341		}
342	
343		if err := tx.Commit(); err != nil {
344			return nil, fmt.Errorf("commit refund tx: %w", err)
345		}
346	
347		if s.logs != nil {
348			_ = s.logs.Log("info", "payment.refund", map[string]any{
349				"original_payment_id": original.ID,
350				"refund_payment_id":   refundPayment.ID,
351				"amount_cents":        input.AmountCents,
352				"reason":              reason,
353				"gateway":             original.Gateway,
354				"request_id":          fallbackRequestID(input.RequestID),
355			})
356		}
357	
358		return s.payments.GetByID(ctx, refundPayment.ID)
359	}
