64			"local_ip":          strings.TrimSpace(ctxMeta.LocalIP),
65			"request_id":        input.RequestID,
66			"timestamp":         now.Format(time.RFC3339Nano),
67		}
68	
69		beforeJSON, err := marshalAuditState(map[string]any{
70			"state_before": input.Before,
71			"metadata":     metadata,
72		})
73		if err != nil {
74			return err
75		}
76	
77		afterJSON, err := marshalAuditState(map[string]any{
78			"state_after": input.After,
79			"metadata":    metadata,
80		})
81		if err != nil {
82			return err
83		}
84	
85		var hashPrev *string
86		if tx != nil {
87			hashPrev, err = s.auditEvents.LastHashTx(ctx, tx)
88		} else {
89			hashPrev, err = s.auditEvents.LastHash(ctx)
90		}
91		if err != nil {
92			return fmt.Errorf("get previous audit hash: %w", err)
93		}
94	
95		occurredAt := now
96		hashSelf := computeAuditHash(hashPrev, occurredAt, input.ActorID, input.Action, input.ResourceType, input.ResourceID, beforeJSON, afterJSON, input.RequestID)
97	
98		event := &domain.AuditEvent{
99			OccurredAt:   occurredAt,
100			ActorID:      input.ActorID,
101			OperatorName: strings.TrimSpace(ctxMeta.OperatorUsername),
102			LocalIP:      strings.TrimSpace(ctxMeta.LocalIP),
103			Action:       input.Action,
104			ResourceType: input.ResourceType,
105			ResourceID:   input.ResourceID,
106			BeforeJSON:   beforeJSON,
107			AfterJSON:    afterJSON,
108			RequestID:    input.RequestID,
109			HashPrev:     hashPrev,
110			HashSelf:     hashSelf,
111		}
112	
113		if tx != nil {
114			err = s.auditEvents.AppendTx(ctx, tx, event)
115		} else {
116			err = s.auditEvents.Append(ctx, event)
117		}
118		if err != nil {
119			return fmt.Errorf("append audit event: %w", err)
120		}
121	
122		return nil
123	}
124	
125	func marshalAuditState(payload map[string]any) (*string, error) {
126		raw, err := json.Marshal(payload)
127		if err != nil {
128			return nil, fmt.Errorf("marshal audit payload: %w", err)
129		}
130		text := string(raw)
131		return &text, nil
132	}
