135		return s.LogEvent(ctx, AuditLogInput{
136			ActorID:      &actorID,
137			Action:       "auth.login.success",
138			ResourceType: "user",
139			ResourceID:   username,
140			After: map[string]any{
141				"outcome":    "success",
142				"ip":         ip,
143				"user_agent": userAgent,
144			},
145			RequestID: requestID,
146		})
