149	func (s *AuditService) LogLoginFailure(ctx context.Context, actorID *int64, username, reason, requestID, ip, userAgent string) error {
150		return s.LogEvent(ctx, AuditLogInput{
151			ActorID:      actorID,
152			Action:       "auth.login.failure",
153			ResourceType: "user",
154			ResourceID:   username,
155			After: map[string]any{
156				"outcome":    "failure",
