158				"ip":         ip,
159				"user_agent": userAgent,
160			},
161			RequestID: requestID,
162		})
163	}
164	
165	func computeAuditHash(hashPrev *string, occurredAt time.Time, actorID *int64, action, resourceType, resourceID string, beforeJSON, afterJSON *string, requestID string) string {
166		base := ""
167		if hashPrev != nil {
168			base = *hashPrev
169		}
170	
171		actor := ""
172		if actorID != nil {
173			actor = strconv.FormatInt(*actorID, 10)
174		}
175	
176		before := ""
177		if beforeJSON != nil {
178			before = *beforeJSON
179		}
180	
181		after := ""
182		if afterJSON != nil {
183			after = *afterJSON
184		}
185	
186		payload := base + "|" + occurredAt.Format(time.RFC3339Nano) + "|" + actor + "|" + action + "|" + resourceType + "|" + resourceID + "|" + before + "|" + after + "|" + requestID
187		digest := sha256.Sum256([]byte(payload))
188		return hex.EncodeToString(digest[:])
189	}
