1	package service
2	
3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/rand"
7		"encoding/base64"
8		"errors"
9		"fmt"
10		"io"
11	)
12	
13	var ErrInvalidCiphertext = errors.New("invalid encrypted payload")
14	
15	type FieldCipher struct {
16		aead cipher.AEAD
17	}
18	
19	func NewFieldCipherFromBase64(masterKeyBase64 string) (*FieldCipher, error) {
20		rawKey, err := base64.StdEncoding.DecodeString(masterKeyBase64)
21		if err != nil {
22			return nil, fmt.Errorf("decode master key: %w", err)
23		}
24		if len(rawKey) != 32 {
25			return nil, errors.New("master key must be 32 bytes for AES-256-GCM")
26		}
27	
28		block, err := aes.NewCipher(rawKey)
29		if err != nil {
30			return nil, fmt.Errorf("create cipher block: %w", err)
31		}
32	
33		aead, err := cipher.NewGCM(block)
34		if err != nil {
35			return nil, fmt.Errorf("create gcm: %w", err)
36		}
37	
38		return &FieldCipher{aead: aead}, nil
39	}
40	
41	func (f *FieldCipher) Encrypt(plaintext []byte) (string, error) {
42		nonce := make([]byte, f.aead.NonceSize())
43		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
44			return "", fmt.Errorf("read nonce: %w", err)
45		}
46	
47		ciphertext := f.aead.Seal(nil, nonce, plaintext, nil)
48		payload := append(nonce, ciphertext...)
49	
50		return base64.StdEncoding.EncodeToString(payload), nil
51	}
52	
53	func (f *FieldCipher) Decrypt(payload string) ([]byte, error) {
54		raw, err := base64.StdEncoding.DecodeString(payload)
55		if err != nil {
56			return nil, ErrInvalidCiphertext
57		}
58	
59		nonceSize := f.aead.NonceSize()
60		if len(raw) < nonceSize {
61			return nil, ErrInvalidCiphertext
62		}
63	
64		nonce := raw[:nonceSize]
65		ciphertext := raw[nonceSize:]
66	
67		plaintext, err := f.aead.Open(nil, nonce, ciphertext, nil)
68		if err != nil {
69			return nil, ErrInvalidCiphertext
70		}
71	
72		return plaintext, nil
73	}
