21	func (h *KPIHandler) ServiceDelivery(c *fiber.Ctx) error {
22		now := time.Now().UTC()
23		from := now.Add(-24 * time.Hour)
24		to := now
25	
26		if fromRaw := strings.TrimSpace(c.Query("from")); fromRaw != "" {
27			parsed, err := time.Parse(time.RFC3339, fromRaw)
28			if err != nil {
29				return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "from must be RFC3339 timestamp", nil)
30			}
31			from = parsed.UTC()
32		}
33	
34		if toRaw := strings.TrimSpace(c.Query("to")); toRaw != "" {
35			parsed, err := time.Parse(time.RFC3339, toRaw)
36			if err != nil {
37				return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "to must be RFC3339 timestamp", nil)
38			}
39			to = parsed.UTC()
40		}
41	
42		groupBy := strings.TrimSpace(c.Query("group_by"))
43		items, err := h.kpis.QueryServiceDelivery(c.UserContext(), service.ServiceDeliveryQuery{
44			From:    from,
45			To:      to,
46			GroupBy: groupBy,
47		})
48		if err != nil {
49			return handleServiceError(c, err, "Failed to query service delivery KPIs")
50		}
51	
52		return httpx.OK(c, fiber.StatusOK, fiber.Map{
53			"group_by": groupByOrDefault(groupBy),
54			"from":     from.Format(time.RFC3339),
55			"to":       to.Format(time.RFC3339),
56			"items":    items,
57		})
