26	func (h *MediaHandler) Upload(c *fiber.Ctx) error {
27		exerciseID, err := strconv.ParseInt(strings.TrimSpace(c.FormValue("exercise_id")), 10, 64)
28		if err != nil || exerciseID <= 0 {
29			return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "exercise_id must be a positive integer", nil)
30		}
31	
32		mediaType := strings.TrimSpace(c.FormValue("media_type"))
33		variant := strings.TrimSpace(c.FormValue("variant"))
34	
35		var durationMS *int64
36		if durationRaw := strings.TrimSpace(c.FormValue("duration_ms")); durationRaw != "" {
37			v, err := strconv.ParseInt(durationRaw, 10, 64)
38			if err != nil || v < 0 {
39				return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "duration_ms must be a non-negative integer", nil)
40			}
41			durationMS = &v
42		}
43	
44		fileHeader, err := c.FormFile("file")
45		if err != nil {
46			return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "file is required", nil)
47		}
48	
49		file, err := fileHeader.Open()
50		if err != nil {
51			return httpx.Error(c, fiber.StatusInternalServerError, "INTERNAL_ERROR", "Failed to open uploaded file", nil)
52		}
53		defer file.Close()
54	
55		asset, err := h.media.Ingest(c.UserContext(), service.IngestMediaInput{
56			ExerciseID: exerciseID,
57			MediaType:  mediaType,
58			Variant:    variant,
59			Filename:   fileHeader.Filename,
60			DurationMS: durationMS,
61			Reader:     file,
62		})
63		if err != nil {
64			return handleServiceError(c, err, "Failed to ingest media file")
65		}
66	
67		return httpx.OK(c, fiber.StatusCreated, fiber.Map{"media": asset})
68	}
