70	func (h *MediaHandler) Get(c *fiber.Ctx) error {
71		mediaID, err := strconv.ParseInt(c.Params("media_id"), 10, 64)
72		if err != nil || mediaID <= 0 {
73			return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "media_id must be a positive integer", nil)
74		}
75	
76		asset, err := h.media.GetByID(c.UserContext(), mediaID)
77		if err != nil {
78			return handleServiceError(c, err, "Failed to fetch media metadata")
79		}
80	
81		return httpx.OK(c, fiber.StatusOK, fiber.Map{"media": asset})
82	}
83	
84	func (h *MediaHandler) Stream(c *fiber.Ctx) error {
85		mediaID, err := strconv.ParseInt(c.Params("media_id"), 10, 64)
86		if err != nil || mediaID <= 0 {
87			return httpx.Error(c, fiber.StatusUnprocessableEntity, "VALIDATION_ERROR", "media_id must be a positive integer", nil)
88		}
89	
90		asset, err := h.media.GetByID(c.UserContext(), mediaID)
91		if err != nil {
92			return handleServiceError(c, err, "Failed to fetch media asset")
93		}
94	
95		absPath := h.media.ResolvePath(asset.Path)
96		file, err := os.Open(absPath)
97		if err != nil {
98			return httpx.Error(c, fiber.StatusNotFound, "NOT_FOUND", "Media file not found on disk", nil)
99		}
100		defer file.Close()
101	
102		info, err := file.Stat()
103		if err != nil {
104			return httpx.Error(c, fiber.StatusInternalServerError, "INTERNAL_ERROR", "Failed to inspect media file", nil)
105		}
106	
107		totalSize := info.Size()
108		contentType := asset.MediaType
109		if strings.TrimSpace(contentType) == "" {
110			contentType = mime.TypeByExtension(filepath.Ext(absPath))
111			if contentType == "" {
112				contentType = "application/octet-stream"
113			}
114		}
115	
116		c.Set("Accept-Ranges", "bytes")
117		c.Set("Content-Type", contentType)
118	
119		rangeHeader := strings.TrimSpace(c.Get("Range"))
120		if rangeHeader == "" {
121			c.Set("Content-Length", strconv.FormatInt(totalSize, 10))
122			return c.Status(fiber.StatusOK).SendStream(file, int(totalSize))
123		}
124	
125		start, end, err := parseRange(rangeHeader, totalSize)
126		if err != nil {
127			c.Set("Content-Range", fmt.Sprintf("bytes */%d", totalSize))
128			return c.SendStatus(fiber.StatusRequestedRangeNotSatisfiable)
129		}
130	
131		if _, err := file.Seek(start, io.SeekStart); err != nil {
132			return httpx.Error(c, fiber.StatusInternalServerError, "INTERNAL_ERROR", "Failed to seek media stream", nil)
133		}
134	
135		length := end - start + 1
136		c.Set("Content-Range", fmt.Sprintf("bytes %d-%d/%d", start, end, totalSize))
137		c.Set("Content-Length", strconv.FormatInt(length, 10))
138	
139		return c.Status(fiber.StatusPartialContent).SendStream(io.LimitReader(file, length), int(length))
140	}
141	
142	func parseRange(header string, total int64) (int64, int64, error) {
143		if !strings.HasPrefix(header, "bytes=") {
144			return 0, 0, fmt.Errorf("invalid range unit")
145		}
146	
147		raw := strings.TrimPrefix(header, "bytes=")
148		if strings.Contains(raw, ",") {
149			return 0, 0, fmt.Errorf("multiple ranges not supported")
150		}
151	
152		parts := strings.SplitN(raw, "-", 2)
153		if len(parts) != 2 {
154			return 0, 0, fmt.Errorf("invalid range format")
155		}
156	
157		startPart := strings.TrimSpace(parts[0])
158		endPart := strings.TrimSpace(parts[1])
159	
160		if startPart == "" {
161			suffix, err := strconv.ParseInt(endPart, 10, 64)
162			if err != nil || suffix <= 0 {
163				return 0, 0, fmt.Errorf("invalid suffix range")
164			}
165			if suffix > total {
166				suffix = total
167			}
168			return total - suffix, total - 1, nil
169		}
170	
171		start, err := strconv.ParseInt(startPart, 10, 64)
172		if err != nil || start < 0 || start >= total {
173			return 0, 0, fmt.Errorf("invalid start range")
174		}
175	
176		if endPart == "" {
177			return start, total - 1, nil
178		}
179	
180		end, err := strconv.ParseInt(endPart, 10, 64)
181		if err != nil || end < start {
182			return 0, 0, fmt.Errorf("invalid end range")
183		}
184		if end >= total {
185			end = total - 1
186		}
187	
188		return start, end, nil
189	}
