	return c.SendString(`
<section id="cache-lru-simulator" class="cache-simulator">
  <h3>Client LRU Cache</h3>
  <p>IndexedDB-backed cache for recently viewed exercise content and media. Limits: 2 GB total or 200 items.</p>
