    var DB_NAME = 'clinic_lru_cache';
    var STORE_NAME = 'cache_items';
    var DB_VERSION = 1;
    var MAX_BYTES = 2 * 1024 * 1024 * 1024;
    var MAX_ITEMS = 200;

    function openDB() {
      return new Promise(function(resolve, reject) {
        var request = indexedDB.open(DB_NAME, DB_VERSION);
