		UserAgent: "test",
	})
	if err != nil {
		t.Fatalf("login: %v", err)
	}

	// Token should be valid immediately
	user, _, err := authService.AuthenticateToken(ctx, result.Token)
	if err != nil {
		t.Fatalf("authenticate valid token: %v", err)
