{"file_path": "C:\Users\PC\Documents\Eaglepoint\TASK-54\repo\unit_tests\audit_hash_chain_test.go", "content": "package unit_tests

import (
	"context"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"strconv"
	"testing"
	"time"

	"clinic-admin-suite/internal/domain"
	"clinic-admin-suite/internal/repository/sqlite"
	"clinic-admin-suite/internal/service"
)

func TestAuditHashChainIntegrity(t *testing.T) {
	ctx := context.Background()
	db := setupTestDB(t)

	auditRepo := sqlite.NewAuditRepository(db)
	auditService := service.NewAuditService(auditRepo)

	// Create multiple audit events
	for i := 0; i < 5; i++ {
		actorID := int64(1)
		err := auditService.LogEvent(ctx, service.AuditLogInput{
			ActorID:      &actorID,
			Action:       "test.action." + strconv.Itoa(i),
			ResourceType: "test_resource",
			ResourceID:   strconv.Itoa(i),
			After:        map[string]any{"value": i},
			RequestID:    "req_hash_chain_" + strconv.Itoa(i),
		})
		if err != nil {
			t.Fatalf("log event %d: %v", i, err)
		}
	}

	// Read all audit events
	rows, err := db.QueryContext(ctx, `SELECT id, occurred_at, actor_id, action, resource_type, resource_id, before_json, after_json, request_id, hash_prev, hash_self FROM audit_events ORDER BY id ASC`)
	if err != nil {
		t.Fatalf("query audit events: %v", err)
	}
	defer rows.Close()

	var events []domain.AuditEvent
	for rows.Next() {
		var event domain.AuditEvent
		var occurredAtUnix int64
		var actorID sql.NullInt64
		var hashPrev sql.NullString
		var beforeJSON, afterJSON sql.NullString

		if err := rows.Scan(&event.ID, &occurredAtUnix, &actorID, &event.Action, &event.ResourceType, &event.ResourceID, &beforeJSON, &afterJSON, &event.RequestID, &hashPrev, &event.HashSelf); err != nil {
			t.Fatalf("scan event: %v", err)
		}
		event.OccurredAt = time.Unix(occurredAtUnix, 0).UTC()
		if actorID.Valid {
			v := actorID.Int64
			event.ActorID = &v
		}
		if hashPrev.Valid {
			event.HashPrev = &hashPrev.String
		}
		if beforeJSON.Valid {
			event.BeforeJSON = &beforeJSON.String
		}
		if afterJSON.Valid {
			event.AfterJSON = &afterJSON.String
		}
		events = append(events, event)
	}

	if len(events) < 5 {
		t.Fatalf("expected at least 5 audit events, got %d", len(events))
	}

	// Verify hash chain: each event's hash_self should chain from hash_prev
	for i, event := range events {
		expectedHash := computeTestAuditHash(
			event.HashPrev,
			event.OccurredAt,
			event.ActorID,
			event.Action,
			event.ResourceType,
			event.ResourceID,
			event.BeforeJSON,
			event.AfterJSON,
			event.RequestID,
		)

		if event.HashSelf != expectedHash {
			t.Fatalf("event %d (id=%d): hash_self mismatch: expected %s, got %s", i, event.ID, expectedHash, event.HashSelf)
		}

		// Verify chain continuity
		if i == 0 {
			// First event may have nil hash_prev
			continue
		}
		prevEvent := events[i-1]
		if event.HashPrev == nil {
			t.Fatalf("event %d: hash_prev should not be nil (should reference previous event)", i)
		}
		if *event.HashPrev != prevEvent.HashSelf {
			t.Fatalf("event %d: hash_prev (%s) does not match previous event's hash_self (%s)", i, *event.HashPrev, prevEvent.HashSelf)
		}
	}
}

func TestAuditHashChainDetectsTampering(t *testing.T) {
	ctx := context.Background()
	db := setupTestDB(t)

	auditRepo := sqlite.NewAuditRepository(db)
	auditService := service.NewAuditService(auditRepo)

	// Create a chain of 3 events
	for i := 0; i < 3; i++ {
		actorID := int64(1)
		err := auditService.LogEvent(ctx, service.AuditLogInput{
			ActorID:      &actorID,
			Action:       "tamper.test." + strconv.Itoa(i),
			ResourceType: "tamper_resource",
			ResourceID:   strconv.Itoa(i),
			After:        map[string]any{"value": i},
			RequestID:    "req_tamper_" + strconv.Itoa(i),
		})
		if err != nil {
			t.Fatalf("log event %d: %v", i, err)
		}
	}

	// Tamper with the second event's after_json
	tamperedJSON, _ := json.Marshal(map[string]any{"state_after": map[string]any{"value": 999}, "metadata": map[string]any{}})
	_, err := db.ExecContext(ctx, `UPDATE audit_events SET after_json = ? WHERE id = 2`, string(tamperedJSON))
	if err != nil {
		t.Fatalf("tamper update: %v", err)
	}

	// Re-read and verify chain is broken
	rows, err := db.QueryContext(ctx, `SELECT id, occurred_at, actor_id, action, resource_type, resource_id, before_json, after_json, request_id, hash_prev, hash_self FROM audit_events ORDER BY id ASC`)
	if err != nil {
		t.Fatalf("query: %v", err)
	}
	defer rows.Close()

	tamperDetected := false
	for rows.Next() {
		var event domain.AuditEvent
		var occurredAtUnix int64
		var actorID sql.NullInt64
		var hashPrev sql.NullString
		var beforeJSON, afterJSON sql.NullString

		if err := rows.Scan(&event.ID, &occurredAtUnix, &actorID, &event.Action, &event.ResourceType, &event.ResourceID, &beforeJSON, &afterJSON, &event.RequestID, &hashPrev, &event.HashSelf); err != nil {
			t.Fatalf("scan: %v", err)
		}
		event.OccurredAt = time.Unix(occurredAtUnix, 0).UTC()
		if actorID.Valid {
			v := actorID.Int64
			event.ActorID = &v
		}
		if hashPrev.Valid {
			event.HashPrev = &hashPrev.String
		}
		if beforeJSON.Valid {
			event.BeforeJSON = &beforeJSON.String
		}
		if afterJSON.Valid {
			event.AfterJSON = &afterJSON.String
		}

		expectedHash := computeTestAuditHash(event.HashPrev, event.OccurredAt, event.ActorID, event.Action, event.ResourceType, event.ResourceID, event.BeforeJSON, event.AfterJSON, event.RequestID)
		if event.HashSelf != expectedHash {
			tamperDetected = true
			break
		}
	}

	if !tamperDetected {
		t.Fatal("expected tampering to be detected by hash chain verification")
	}
}

// computeTestAuditHash reproduces the same hash computation as the audit service
func computeTestAuditHash(hashPrev *string, occurredAt time.Time, actorID *int64, action, resourceType, resourceID string, beforeJSON, afterJSON *string, requestID string) string {
	base := ""
	if hashPrev != nil {
		base = *hashPrev
	}
	actor := ""
	if actorID != nil {
		actor = strconv.FormatInt(*actorID, 10)
	}
	before := ""
	if beforeJSON != nil {
		before = *beforeJSON
	}
	after := ""
	if afterJSON != nil {
		after = *afterJSON
	}
	payload := base + "|" + occurredAt.Format(time.RFC3339Nano) + "|" + actor + "|" + action + "|" + resourceType + "|" + resourceID + "|" + before + "|" + after + "|" + requestID
	digest := sha256.Sum256([]byte(payload))
	return hex.EncodeToString(digest[:])
}
"}

